    'page_history' => 'Broadcast History',
    'page_history_desc' => 'View a complete history of all sent broadcasts with status, timestamps, and the ability to view details or resend.',
    'page_scheduled' => 'Scheduled Broadcasts',
    'page_scheduled_desc' => 'List view of all scheduled broadcasts showing scheduled time, repeat settings, and status.',
    'page_calendar' => 'Calendar',
    'page_calendar_desc' => 'Visual calendar showing all scheduled broadcasts color-coded by webhook. Click events for details.',
    'page_templates' => 'Templates',
    'page_templates_desc' => 'Manage your personal and global broadcast templates. Create, edit, and delete templates.',
    'page_webhooks' => 'Webhooks',
    'page_webhooks_desc' => 'Manage Discord webhooks including creating, editing, testing, and deleting webhook configurations.',
    'page_config' => 'Settings',
    'page_config_desc' => 'Central settings page with seven tabs: Webhooks, Discord Roles, Discord Channels, Staging Locations, PAP Types, Structure Timers, and Routing Map.',
    'page_opportunities' => 'FC Opportunities',
    'page_opportunities_desc' => 'Focused board for fleet commanders: upcoming structure timers and fleet ops with live countdowns, severity, and one-click form-up broadcasts. Sidebar entry only appears when Manager Core and Structure Manager are installed.',
    'page_diagnostic' => 'Diagnostic',
    'page_diagnostic_desc' => 'Admin-only operational surface for troubleshooting webhook delivery, event subscriptions, and integration health. Six tabs (Health Checks, Master Test, System Validation, Settings Health, Data Integrity, Broadcast Trace) cover stats / deep checks / row counts / pipeline tracing. Not in the sidebar — reach via /discord-pings/diagnostic. Requires the new "Plugin Admin" permission.',

    // Commands
    'commands' => 'Commands',
    'commands_intro' => 'The plugin provides several Artisan commands for maintenance and automation.',
    'command_process_scheduled' => 'Process Scheduled Broadcasts',
    'command_process_scheduled_desc' => 'Processes all due scheduled broadcasts and sends them. This command runs automatically via the Laravel scheduler.',
    'command_cleanup' => 'Cleanup History',
    'command_cleanup_desc' => 'Removes old broadcast history entries (default: 90 days) and prunes resolved structure timers from the calendar ingest table (default: 14 days). Both retention windows are configurable in `discordpings.config.php`.',
    'scheduler_note' => 'Scheduler',
    'scheduler_note_desc' => 'The process-scheduled command runs automatically every minute via Laravel\'s task scheduler. Ensure your cron is configured: * * * * * cd /path-to-seat && php artisan schedule:run >> /dev/null 2>&1',

    // Permissions
    'permissions' => 'Permissions',
    'permissions_intro' => 'SeAT Broadcast uses a granular permission system that maps cleanly to real-world fleet roles. Each permission below grants a specific capability; mix them per SeAT role to model your corp/alliance hierarchy. The scheduled-broadcast surfaces (Calendar, FC Opportunities, scheduled list) use a two-tier model: <strong>Send Discord Pings</strong> is the regular-FC tier (own pings only), and <strong>Manage All Scheduled Pings</strong> is the "Fleet Coordinator" tier that adds visibility and control over OTHER users\' pings.',

    'permissions_tier_model_title' => 'Two-Tier Model for Scheduling + Planning',
    'permissions_tier_model_desc' => 'Every scheduled-broadcast surface (the Scheduled Broadcasts list, the Calendar, the FC Opportunities planner) uses the same two-tier visibility model. Choose the tier per user based on what they\'re trusted to do.',

    'permissions_scenarios_title' => 'Common Role Recipes',
    'permissions_scenarios_desc' => 'Five recipes that cover the typical SeAT install. Use them as a starting point; mix and match as your corp/alliance grows.',

    'permissions_reference_title' => 'Full Permission Reference',
    'permissions_reference_desc' => 'Every permission the plugin offers, in approximate "you-need-this-first" order.',
    'perm_view' => 'View Discord Pings - Basic access to the plugin.',
    'perm_send' => 'Send Discord Pings - Send broadcasts to a single webhook (manual + scheduled). Includes access to the Scheduled Broadcasts list, Calendar, and FC Opportunities planner — limited to the user\'s OWN scheduled pings. Pair with Manage All Scheduled Pings for the Fleet Coordinator tier.',
    'perm_send_multiple' => 'Send to Multiple Webhooks - Send broadcasts to multiple webhooks at once.',
    'perm_manage_webhooks' => 'Manage Webhooks - Create, edit, and delete Discord webhooks and configuration.',
    'perm_view_history' => 'View Ping History - View your own broadcast history.',
    'perm_view_all_history' => 'View All History - View broadcast history from all users.',
    'perm_manage_scheduled' => 'Manage All Scheduled Pings - The "Fleet Coordinator" tier. Adds visibility and control over OTHER users\' scheduled pings (the list and calendar views become full-org views) plus the bulk-clear of inactive pings. Regular FCs with just Send Discord Pings already manage their own scheduled pings without this.',
    'perm_manage_templates' => 'Manage Templates - Create, edit, and delete your own broadcast templates.',
    'perm_manage_global_templates' => 'Manage Global Templates - Manage global templates visible to all users.',
    'perm_admin' => 'Plugin Admin - Access the diagnostic page (Health Checks, Master Test, System Validation, Settings Health, Data Integrity, Broadcast Trace). Admin-only operational surface.',

    // FAQ
    'faq' => 'Frequently Asked Questions',
    'faq_q1' => 'Why is my broadcast not appearing in Discord?',
    'faq_a1' => 'Check that the webhook URL is correct and the webhook is active. Use the test button on the webhook configuration page. Also verify the webhook has not been deleted from Discord server settings.',
    'faq_q2' => 'What timezone are scheduled broadcasts in?',
    'faq_a2' => 'All scheduled broadcasts use EVE time (UTC). The scheduling form includes a timezone selector to help convert your local time to EVE time.',
    'faq_q3' => 'Can I send to multiple Discord servers?',
    'faq_a3' => 'Yes. Create webhooks for channels in different Discord servers and use the "Multiple Webhooks" feature to send to all of them at once.',
    'faq_q4' => 'How do I mention a specific Discord role?',
    'faq_a4' => 'First, add the role in Settings > Discord Roles with its role ID. Then when composing a broadcast, select "Discord Role" as the mention type and choose the role from the dropdown.',
    'faq_q5' => 'What happens when a scheduled broadcast fails?',
    'faq_a5' => 'Failed broadcasts are logged in the history with the error message. Recurring broadcasts will continue to fire at their next scheduled time regardless of individual failures.',
    'faq_q6' => 'Can other users see my templates?',
    'faq_a6' => 'Only if they are marked as Global. Personal templates are only visible to the user who created them. Administrators can toggle templates between personal and global.',
    'faq_q7' => 'How do I link a doctrine from the fitting plugin?',
    'faq_a7' => 'If you have the seat-fitting plugin installed (CryptaTech or Denngarr version), doctrines will appear in a dropdown on the send form. Select a doctrine and it will be included as a clickable link in the Discord embed.',
    'faq_q8' => 'What is the maximum message length?',
    'faq_a8' => 'Messages are limited to 2000 characters, matching Discord\'s own message limit. The character counter on the send form helps you stay within this limit.',
    'faq_q9' => 'How do I find my Discord role/channel IDs?',
    'faq_a9' => 'Enable Developer Mode in Discord (Settings > Advanced > Developer Mode). Then right-click any role or channel and select "Copy ID". For channels, you can also copy the channel URL directly.',
    'faq_q10' => 'Can I edit a scheduled broadcast?',
    'faq_a10' => 'Yes. Click the edit (pencil) button on any active scheduled ping in the list, or use the Edit button in the calendar event popup. For recurring pings that have already fired, editing applies to all future occurrences from the new scheduled time; past sends are preserved in history.',
    'faq_q11' => 'Why don\'t I see FC Opportunities in the sidebar?',
    'faq_a11' => 'FC Opportunities is hidden when Manager Core or Structure Manager is not installed (the board has nothing to surface without them). Install both, restart your SeAT stack, and the entry appears. If your install runs `php artisan config:cache`, clear the cache after installing the dependencies.',
    'faq_q12' => 'How do I send a form-up broadcast for a structure timer?',
    'faq_a12' => 'From the FC Opportunities board click the green "Form-up" button on the row, or from the Calendar click the timer and use "Schedule formup ping" in the modal. Either path opens the Scheduled Broadcast form pre-filled with the op details (scheduled time = timer minus your configured lead time, formup = system, scaffolded message). Review, adjust, submit.',
    'faq_q13' => 'How do I change the 30-minute default form-up lead time?',
    'faq_a13' => 'Settings > Structure Timers tab > "Default form-up lead time (minutes)". Range: 5 minutes to 12 hours. The change takes effect for new form-up broadcasts scheduled afterwards; broadcasts already scheduled keep their original time.',

    // Troubleshooting
    'troubleshooting' => 'Troubleshooting',
    'issue_webhook_fail_title' => 'Webhook test fails',
    'issue_webhook_fail_solution1' => 'Verify the webhook URL starts with https://discord.com/api/webhooks/',
    'issue_webhook_fail_solution2' => 'Check that the webhook has not been deleted in Discord server settings.',
    'issue_webhook_fail_solution3' => 'Ensure your server can reach Discord\'s API (no firewall blocking outbound HTTPS).',
    'issue_scheduled_not_sending_title' => 'Scheduled broadcasts are not sending',
    'issue_scheduled_not_sending_solution1' => 'Verify the Laravel scheduler is running: the cron job should execute php artisan schedule:run every minute.',
    'issue_scheduled_not_sending_solution2' => 'Check that the scheduled ping is active and the scheduled time has passed.',
    'issue_scheduled_not_sending_solution3' => 'Review Laravel logs for any error messages from the ProcessScheduledPings command.',
    'issue_no_permissions_title' => 'Users cannot access plugin features',
    'issue_no_permissions_solution1' => 'Check that the appropriate permissions are assigned in SeAT\'s role management (Settings > Roles).',
    'issue_no_permissions_solution2' => 'Permissions are auto-registered by the plugin on boot from `src/Config/Permissions/discordpings.permissions.php`; if a permission is missing, restart your SeAT stack so the service provider re-runs its registration.',
    'issue_no_permissions_solution3' => 'Ensure the user has the base "View Discord Pings" permission for plugin access.',
    'issue_mentions_not_working_title' => 'Mentions are not pinging users in Discord',
    'issue_mentions_not_working_solution1' => 'Mentions are configured on the Send Broadcast / Schedule form via the Mentions selector (@everyone, @here, Discord Role, or Custom). There is no separate per-webhook "Enable Mentions" toggle.',
    'issue_mentions_not_working_solution2' => 'For role mentions, verify the role ID is correct and the role is mentionable in Discord server settings.',
    'issue_mentions_not_working_solution3' => 'Check that the webhook bot has permission to mention @everyone / @here in the target channel.',
    'issue_fc_opps_empty_title' => 'FC Opportunities board is empty or sidebar entry missing',
    'issue_fc_opps_empty_solution1' => 'The board requires Manager Core and Structure Manager. Confirm both are installed; the Settings > Structure Timers tab shows their live detection status.',
    'issue_fc_opps_empty_solution2' => 'After installing the dependencies, restart your SeAT stack so the plugin\'s service provider re-evaluates the sidebar conditional and the EventBus subscription registers.',
    'issue_fc_opps_empty_solution3' => 'If your install runs `php artisan config:cache`, clear the cache (`php artisan config:clear`) so the conditional sidebar entry re-evaluates.',
    'issue_fc_opps_empty_solution4' => 'If MC + SM are installed but no events are flowing, check Manager Core\'s diagnostic page for the seat-discord-pings subscription on pattern `structure_manager.timer.*`.',

    // What's New
    'whats_new' => 'What\'s New',
    'whats_new_intro' => 'Recent updates and new features added to SeAT Broadcast.',

    // v2.0.0 markers + What's New callout (Overview section)
    'v2_badge'  => 'NEW in v2.0.0',
    'mc_badge'  => 'Requires Manager Core',
    'whats_new_v2_title'  => 'What\'s New in v2.0.0: The Planning HUB Era',
    'whats_new_v2_intro'  => 'SeAT Broadcast steps up from a standalone Discord webhook sender into the <strong>Planning HUB</strong> for fleet commanders. With <strong>Manager Core</strong> and <strong>Structure Manager</strong> installed, structure timers and fleet ops flow onto the Broadcasts Calendar and a dedicated <strong>FC Opportunities</strong> board, and one click on any op opens a pre-filled form-up broadcast.',
    'whats_new_v2_list'   => '<ul>
        <li><strong>FC Opportunities board</strong>: focused FC view of upcoming structure timers, mining extractions and manual fleet ops, with live countdowns, severity, and a one-click <em>Form-up</em> button (sidebar entry hidden without Manager Core + Structure Manager)</li>
        <li><strong>Calendar / Planner split</strong>: tactical events (structure timers + mining extractions) live exclusively on FC Opportunities. The Broadcasts Calendar stays strictly broadcast-focused (scheduled + manual sent pings), uncluttered by timers. Form-up pings created from the board land on the calendar naturally</li>
        <li><strong>Structure timer ingest</strong>: auto-detected reinforce / anchor / fuel timers and manual fleet ops flow in via Manager Core\'s EventBus, colour-coded by severity, surfaced on FC Opportunities</li>
        <li><strong>Mining extraction ingest</strong>: moon extractions from Mining Manager v2.0.1+ appear on FC Opportunities as a distinct ⛏️ mining category with a 48h fleet-able window, multi-FC friendly, with optional T-2h pre-expiry alerts</li>
        <li><strong>Pre-event reminder pings</strong>: flagged webhooks get automatic Discord embeds at T-24h and T-1h before structure timers, plus a single T-2h alert before mining extractions expire</li>
        <li><strong>Settings &gt; Structure Timers tab</strong>: master alert toggles (structure and mining), default form-up lead time, plus live Manager Core / Structure Manager / Mining Manager detection</li>
        <li><strong>EVE → local time</strong>: every EVE timestamp in the plugin gains a hover tooltip with your browser-local time; high-priority surfaces (Calendar, FC Opportunities, scheduled list) also show an inline "· HH:MM local" pill. The Scheduled Broadcast form has an Enter In: [EVE/Local] toggle, DST-safe</li>
        <li><strong>Published events</strong>: <code>pings.broadcast.sent</code> and <code>pings.formup.scheduled</code> publish to Manager Core\'s EventBus so HR Manager (or any subscriber) can track active FC activity without reading SeAT Broadcast\'s database</li>
        <li><strong>Hardening pass</strong>: webhook URLs encrypted at rest, restored TLS verification, queued sends, per-webhook rate limits</li>
    </ul>',
    'whats_new_v2_upgrade_note' => 'Upgrade is in place: no manual steps beyond <code>composer update</code> and restarting your SeAT stack (migrations auto-run). The internal PHP namespace was renamed from <code>MattFalahe\\Seat\\DiscordPings</code> to <code>DiscordPings</code>; if your install runs <code>php artisan route:cache</code>, clear it once after the upgrade.',
    'fc_opportunities_requires_title' => 'Requires Manager Core and Structure Manager',
    'fc_opportunities_requires_desc'  => 'The FC Opportunities board surfaces structure timers and fleet ops ingested via Manager Core\'s EventBus from Structure Manager. The sidebar entry is hidden when either plugin is missing; the board itself shows an empty-state with install instructions for anyone reaching it via a deep link.',
    'whats_new_fc_opportunities_title' => '🎯 FC Opportunities Board (2.0.0)',
    'whats_new_fc_opportunities_desc' => 'A new FC Opportunities sidebar entry lists upcoming structure timers and fleet ops in a focused board with countdowns, severity, op type, and a one-click "Form-up" button that opens the Scheduled Broadcast form pre-filled from the op. The Calendar event modal also gains a "Schedule formup ping" button and shows a "📡 N scheduled" badge per op once a form-up broadcast has been planned. Plus a configurable default form-up lead time (in minutes) on the Settings > Structure Timers tab.',
    'whats_new_structure_timers_title' => '🛰️ Structure Timers on the Calendar',
    'whats_new_structure_timers_desc' => 'With Manager Core and Structure Manager installed, structure timers and fleet ops now appear automatically on the Broadcasts Calendar through Manager Core\'s EventBus. Webhooks can be flagged to send pre-timer reminder pings at T-24h and T-1h. See the Structure Timers section for full details. This integration is optional: SeAT Broadcast continues to work standalone when Manager Core is not installed.',
    'whats_new_prepping_title' => '‼️ PREPING ‼️ Broadcast Type',
    'whats_new_prepping_desc' => 'A new "‼️ PREPING ‼️" broadcast type is now available alongside Fleet Broadcast, Announcement, and Message. Use it to notify members that a fleet is being staged and is not yet ready to undock. The title appears in Discord exactly as "‼️ PREPING ‼️". Select it from the Broadcast Type dropdown on both the Send and Schedule forms.',
    'whats_new_pap_config_title' => '🏷️ Configurable PAP Types',
    'whats_new_pap_config_desc' => 'PAP types are no longer hardcoded. Admins can now manage them in Settings > PAP Types — add custom types, set sort order, or deactivate ones you do not use. Three defaults (Strategic, Peacetime, CTA) are created automatically on install/update. Active PAP types populate the dropdown on all broadcast forms.',
    'whats_new_colorpicker_title' => '🎨 Visual Color Picker',
    'whats_new_colorpicker_desc' => 'The Embed Color field now includes a colour swatch you can click to open the browser\'s native colour picker. Select a colour visually or continue typing a hex code — both stay in sync at all times. Selecting a different webhook still auto-fills the colour from that webhook\'s default.',
    'whats_new_scheduled_visibility_title' => '👥 Scheduled Pings — Shared Visibility',
    'whats_new_scheduled_visibility_desc' => 'Users with the Manage Scheduled Pings permission now see all users\' scheduled broadcasts in both the list view and the calendar, not just their own. A "Created By" column in the list identifies each ping\'s author. These users can also delete any scheduled broadcast, making it easy to resolve conflicts or prevent overlapping pings. Users without this permission continue to see only their own scheduled pings.',
    'whats_new_calendar_history_title' => '📅 Manual Broadcasts on Calendar',
    'whats_new_calendar_history_desc' => 'The calendar now shows manually sent broadcasts from the Send Broadcast page alongside scheduled ones. History pings render as a coloured dot + broadcast type icon + message — no full bar — so they are easy to distinguish. Sent scheduled pings also remain on the calendar dimmed with a strikethrough until deleted. Visibility follows your history permissions: View Ping History shows your own, View All History shows everyone\'s.',
    'whats_new_bulk_clear_title' => '🧹 Bulk Clear Inactive Scheduled Pings',
    'whats_new_bulk_clear_desc' => 'Directors and admins with the Manage Scheduled Pings permission can now bulk delete sent (inactive) scheduled broadcasts directly from the Scheduled Broadcasts page. Two buttons let you clear pings older than 7 days or older than 30 days in one click — keeping the list clean without touching any upcoming active pings.',
    'whats_new_edit_scheduled_title' => '✏️ Edit Scheduled Broadcasts',
    'whats_new_edit_scheduled_desc' => 'Scheduled broadcasts can now be edited after creation. Use the pencil button in the list or the Edit button in the calendar event popup. All fields are editable. For recurring series that have already fired, a clear notice explains that changes apply from the new scheduled time onwards — past occurrences are never modified. Clicking Edit on a specific future occurrence in the calendar pre-fills the time picker with that occurrence\'s time.',

    // Plugin info (legacy)
    'plugin_version' => 'Plugin Version',
    'plugin_author' => 'Author',
    'github_link' => 'GitHub Repository',
